import { Request, Response, NextFunction } from 'express';
import { GroupService } from './group.service';
import { CreateGroupDTO, UpdateTelegramIdDTO } from './group.dto';
import { validateCreateGroup, validateUpdateTelegramId } from './group.validator';
import { AppError } from '../../middlewares/error-handler';
import { logger } from '../../middlewares/logger';
import { RequestWithUser } from '../../types';

export class GroupController {
  constructor(private groupService: GroupService) {}

  async createGroup(req: RequestWithUser, res: Response, next: NextFunction) {
    try {
      const groupData: CreateGroupDTO = validateCreateGroup(req.body);
      const group = await this.groupService.createGroup(groupData, req.user.id);
      res.status(201).json({ success: true, data: group });
    } catch (error) {
      logger.error('Error creating group', { requestId: req.id, error });
      next(error);
    }
  }

  async getGroup(req: RequestWithUser, res: Response, next: NextFunction) {
    try {
      const group = await this.groupService.getGroup(req.params.id);
      res.json({ success: true, data: group });
    } catch (error) {
      logger.error('Error fetching group', { requestId: req.id, error });
      next(error);
    }
  }

  async linkTelegram(req: Request, res: Response, next: NextFunction) {
    try {
      const telegramData: UpdateTelegramIdDTO = validateUpdateTelegramId(req.body);
      await this.groupService.linkTelegram(req.params.id, telegramData.telegramChatId);
      res.json({ success: true });
    } catch (error) {
      logger.error('Error linking telegram', { requestId: req.id, error });
      next(error);
    }
  }
}

import { GroupRepository } from './group.repository';
import { CreateGroupDTO } from './group.dto';
import { Group } from './group.model';
import { AppError } from '../../middlewares/error-handler';

export class GroupService {
  constructor(private groupRepository: GroupRepository) {}

  async createGroup(groupData: CreateGroupDTO, adminId: string): Promise<Group> {
    try {
      return await this.groupRepository.create({ ...groupData, adminId });
    } catch (error) {
      throw new AppError('GROUP_CREATION_FAILED', 'Failed to create group');
    }
  }

  async getGroup(groupId: string): Promise<Group> {
    const group = await this.groupRepository.findById(groupId);
    if (!group) {
      throw new AppError('GROUP_NOT_FOUND', 'Group not found');
    }
    return group;
  }

  async linkTelegram(groupId: string, telegramChatId: string): Promise<void> {
    const group = await this.getGroup(groupId);
    if (group.telegramChatId) {
      throw new AppError('TELEGRAM_ALREADY_LINKED', 'Telegram already linked');
    }
    await this.groupRepository.updateTelegramChatId(groupId, telegramChatId);
  }
}

import { Group } from './group.model';

export class GroupRepository {
  async create(data: Partial<Group>): Promise<Group> {
    // simulate interaction with the database
    const newGroup = new Group(data);
    await newGroup.save();
    return newGroup;
  }

  async findById(groupId: string): Promise<Group | null> {
    return await Group.findById(groupId).exec();
  }

  async updateTelegramChatId(groupId: string, telegramChatId: string): Promise<void> {
    await Group.updateOne({ _id: groupId }, { telegramChatId }).exec();
  }
}

import { z } from 'zod';
import { CreateGroupDTO, UpdateTelegramIdDTO } from './group.dto';

// Validation schema using Zod
const createGroupSchema = z.object({
  name: z.string().min(1),
  description: z.string().optional(),
});

const updateTelegramIdSchema = z.object({
  telegramChatId: z.string().min(1),
});

export const validateCreateGroup = (data: unknown): CreateGroupDTO => {
  return createGroupSchema.parse(data);
};

export const validateUpdateTelegramId = (data: unknown): UpdateTelegramIdDTO => {
  return updateTelegramIdSchema.parse(data);
};

export interface CreateGroupDTO {
  name: string;
  description?: string;
}

export interface UpdateTelegramIdDTO {
  telegramChatId: string;
}

import mongoose, { Schema, Document } from 'mongoose';

export interface Group extends Document {
  name: string;
  description?: string;
  adminId: mongoose.Types.ObjectId;
  members: mongoose.Types.ObjectId[];
  telegramChatId?: string;
  createdAt: Date;
}

const GroupSchema: Schema = new Schema({
  name: { type: String, required: true },
  description: String,
  adminId: { type: mongoose.Types.ObjectId, required: true },
  members: [{ type: mongoose.Types.ObjectId }],
  telegramChatId: String,
  createdAt: { type: Date, default: Date.now },
});

export const Group = mongoose.model<Group>('Group', GroupSchema);

export class AppError extends Error {
  statusCode: number;
  code: string;

  constructor(code: string, message: string, statusCode = 400) {
    super(message);
    this.statusCode = statusCode;
    this.code = code;
  }
}

export const errorHandler = (err: AppError, req: any, res: any, next: any) => {
  res.status(err.statusCode || 500).json({
    success: false,
    error: err.message,
    code: err.code,
  });
};

import { createLogger, format, transports } from 'winston';

export const logger = createLogger({
  format: format.combine(
    format.timestamp(),
    format.json()
  ),
  transports: [
    new transports.Console(),
  ],
});
